// Merge match + search: prefer match value when present, fallback to search value
function merge(a, b) {
  a = a || {}; b = b || {};
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);
  const out = {};
  for (const k of keys) {
    const va = a[k], vb = b[k];
    if (va !== undefined && va !== null && va !== '') out[k] = va;
    else if (vb !== undefined && vb !== null && vb !== '') out[k] = vb;
    else out[k] = va !== undefined ? va : vb;
  }
  return out;
}

